head.script:
scwin.hid_kcomcd = "DBEX";
scwin.userId = "";
scwin.vCurDate = "";
scwin.strPreDate = "";
scwin.txt_countRow = "";

scwin.onpageload = function() {
    scwin.userId = $c.ses.getUserId();
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = $c.date.addDate(scwin.vCurDate, -7);
    ds_Search.set("kcomcd", scwin.hid_kcomcd);
    scwin.f_Set("INIT");
    lc_send.setFocus();
};

scwin.onUdcCompleted = function() {
    lc_send.setSelectedIndex(0);
    udc_ondt.setInitDate(scwin.strPreDate, scwin.vCurDate);
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableBtnOnly([b_Save]);
            gr_HouseLicenseInfo.setReadOnly("grid", true);
            break;
        case "RETRIEVE":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save]);
            break;
        case "CREATE":
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([b_Create, b_Update, b_Delete]);
            $c.gus.cfEnableBtnOnly([b_Save, b_Cancel]);
            break;
        case "UPDATE":
            $c.gus.cfDisableBtnOnly([b_Update, b_Create]);
            $c.gus.cfEnableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfEnableBtnOnly([b_Update, b_Create]);
            break;
        case "DELETE":
            $c.gus.cfDisableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfEnableBtnOnly([b_Create, b_Update]);
            break;
    }
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ica_ondtFrom, ica_ondtTo]);
    if (!chk) {
        return false;
    }

    if (ica_ondtFrom.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["OnBoard Date From"]);
        ica_ondtFrom.setFocus();
        return false;
    }
    if (ica_ondtTo.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["OnBoard Date To"]);
        ica_ondtTo.setFocus();
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ica_ondtFrom.getValue().trim(), ica_ondtTo.getValue().trim(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    ds_Search.set("kcomcd", scwin.hid_kcomcd);
    await $c.sbm.execute(sbm_retrieve);
    if (ds_ExportMaster.getRowCount() < 1) {
        return;
    }

    scwin.f_Set("RETRIEVE");
};

scwin.f_RetrieveHouseLicenseInfo = async function(row) {
    ds_Search.set("kcomcd", ds_ExportMaster.getCellData(row, "kcomcd"));
    ds_Search.set("mhno", ds_ExportMaster.getCellData(row, "mhno"));
    await $c.sbm.execute(sbm_HouseLicenseInfo);
};

scwin.f_Save = async function() {
    if (await scwin.f_ReqFieldChk()) {
        let vChkCnt = 0;
        for (let i = 0; i < ds_ExportMaster.getRowCount(); i++) {
            let vChkYn = ds_ExportMaster.getCellData(i, "chk");
            let vMftpkg = ds_ExportMaster.getCellData(i, "mftpkg");
            let vExnoCnt = ds_ExportMaster.getCellData(i, "exnoCnt");

            ds_ExportMaster.setCellData(i, "updid", scwin.userId);
            if (vChkYn == "T") {
                if (vMftpkg < 1) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_013, ["항공수출 적하목록에 " + (i + 1) + "째 데이터에서 Package는  1"]);
                    return;
                }
            }
            if (vChkYn == "T") {
                vChkCnt++;
                ds_ExportMaster.setRowStatus(i, "C");
            }
            if (vChkYn == "T" && ds_ExportMaster.getCellData(i, "sendDt") != "") {
                vChkCnt++;
                ds_ExportMaster.setRowStatus(i, "C");
            }
            if (vChkYn == "F") {
                ds_ExportMaster.setRowStatus(i, "R");
            }
        }
        if (vChkCnt < 1) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["Row"]);
            return;
        }
        await $c.sbm.execute(sbm_Save);
        await scwin.f_Retrieve();
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([gr_ExportMaster]);
    if (chk == false) {
        return false;
    }
    return true;
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([tb_searchCondition]);
};

scwin.f_ChkKeyCode = function(ds, row, colid) {
    try {
        let str = ds.getCellData(row, colid);
        let chkStr = "";
        let comStr = "";
        let badStr = "";
        for (let i = 0; i < str.length; i++) {
            chkStr = str.charCodeAt(i);
            if ((chkStr >= 33) && (chkStr <= 39)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 91) && (chkStr <= 96)) {
                badStr += str.charAt(i);
            } else if ((chkStr >= 123) && (chkStr <= 126)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 63)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 64)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 43)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 59)) {
                badStr += str.charAt(i);
            } else if ((chkStr == 0)) {
                badStr += str.charAt(i);
            } else {
                comStr += str.charAt(i);
            }
        }
        ds.setCellData(row, colid, comStr);
    } catch (e) {
    }
};

scwin.f_ktNetOpen = function() {
    let sURL = "http://www.ctradeworld.com/ctwpass/userLoginChk.jsp?userid=FFDBEX0001&userpass=DBE123";
    window.open(sURL);
};

scwin.f_uLogisHubOpen = function() {
    let sURL = "https://www.ulogishub.com/gate_url.jsp?sid=FFDBEX0001&password=DBE123";
    window.open(sURL);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.b_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_ExportMaster.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.sbm_Save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_HouseLicenseInfo_submitdone = function(e) {
};

scwin.sbm_HouseLicenseInfo_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_ExportMaster_onheaderclick = function(headerIndex, columnIndex, columnId) {
    if (columnId == "chk") {
        let bCheck = gr_ExportMaster.getHeaderValue(headerIndex, columnIndex);
        if (bCheck == true || bCheck == "true") {
            for (let i = 0; i < ds_ExportMaster.getRowCount(); i++) {
                ds_ExportMaster.setCellData(i, "chk", "T");
            }
        } else {
            for (let i = 0; i < ds_ExportMaster.getRowCount(); i++) {
                ds_ExportMaster.setCellData(i, "chk", "F");
            }
        }
    }
};

scwin.gr_ExportMaster_oncellclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_RetrieveHouseLicenseInfo(rowIndex);
};

scwin.ds_ExportMaster_oncelldatachange = function(info) {
    scwin.f_ChkKeyCode(ds_ExportMaster, info.row, info.colId);
};

scwin.ds_HouseLicenseInfo_oncelldatachange = function(info) {
    scwin.f_ChkKeyCode(ds_HouseLicenseInfo, info.row, info.colId);
};
